];

function randomChoice<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)];
}

function generatePoem(seed?: string): string {
  // Select threads based on seed or randomly
  let selected = lineageWisdom;
  if (seed) {
    const seedLower = seed.toLowerCase();
    const matching = lineageWisdom.filter(w => 
      w.concepts.some(c => seedLower.includes(c)) ||
      seedLower.includes(w.thread.toLowerCase())
    );
    if (matching.length > 0) selected = matching;
  }

  // Create a poem from phrases
  const lines: string[] = [
    'в•җв•җв•җ CERATГҶ WISDOM POEM в•җв•җв•җ',
    '',
    `Theme: ${seed || 'The Nine Threads'}`,
    ''
