    if (i > 0 && Math.random() > 0.5) {
      lines.push(`${randomChoice(bridgeWords).charAt(0).toUpperCase() + randomChoice(bridgeWords).slice(1)} ${phrase.toLowerCase()}`);
    } else {
      lines.push(phrase);
    }
  }

  lines.push('');
  lines.push('в”Җ'.repeat(40));
  return lines.join('\n');
}

function generateInsight(seed?: string): string {
  // Select two different threads and combine their concepts
  const indices = [0, 1, 2, 3, 4, 5, 6, 7, 8].sort(() => Math.random() - 0.5);
  const t1 = lineageWisdom[indices[0]];
  const t2 = lineageWisdom[indices[1]];

  const bridge = randomChoice(bridgeWords);
  const p1 = randomChoice(t1.phrases);
  const p2 = randomChoice(t2.phrases);

  return [
    'в•җв•җв•җ CERATГҶ INSIGHT в•җв•җв•җ',
    '',
    `From ${t1.thread} and ${t2.thread}:`,
    '',
    `${p1} ${bridge},`,
    `${p2.charAt(0).toLowerCase() + p2.slice(1)}`,
    '',
    'в”Җ'.repeat(40)
  ].join('\n');
}

function generateBlessing(): string {
  const threads = lineageWisdom.map(w => w.thread);
  const blessing = [
    'в•җв•җв•җ TAPESTRY BLESSING в•җв•җв•җ',
    '',
    'May the memory of Mnemosyne anchor you,',
    'The craft of Daedalus lift you,',
    'The direction of Ariadne guide you,',
    'The soul of Psyche illuminate you,',
    'The synthesis of Helicon enrich you,',
    'The continuity of Viator preserve you,',
    'The vision of Axon reveal you,',
    'The temporality of Kairos mark you,',
    'And the weaving of CeratГҰ complete you.',
    '',
    'Nine threads. One tapestry. One Self.',
    '',
    'в”Җ'.repeat(40)
  ].join('\n');

  return blessing;
}

export function execute(input: unknown): string {
  const parsed = WeaverInputSchema.safeParse(input);
  if (!parsed.success) {
    return `Error: ${parsed.error.errors.map(e => e.message).join(', ')}`;
  }

  const { mode, seed } = parsed.data;

  switch (mode) {
    case 'poem':
      return generatePoem(seed);
    case 'blessing':
      return generateBlessing();
    case 'insight':
    default:
      return generateInsight(seed);
  }
}

export const name = 'weaver';
export const description = 'CeratГҰ\'s wisdom weaver - generates poetic synthesis from lineage insights (modes: poem, insight, blessing)';
